/**
 * The full seven-output currency-definition transaction, byte-locked against
 * live `definecurrency` output on VRSCTEST. The defining identity is "kmerg"
 * (i4saPv8…); the expected scripts and the build heights are lifted verbatim
 * from the daemon's response. Two shapes are locked:
 *
 *   - a simple token (options 0x20, pre-allocated) at height 1155439
 *   - a fractional basket with normalized weights, a pre-launch discount, and
 *     min-preconversion (options 0x21) at height 1155466
 *
 * Between them they exercise every output: the identity update, the currency
 * definition, the import/notarization/export stubs (which embed the height), the
 * reserve deposit, and the identity change output. If any serializer drifts, one
 * of these locks breaks. See _ph differential harness notes for the full 10-config
 * matrix this is distilled from.
 */
import { describe, it, expect } from 'vitest';
import { buildCurrencyLaunchOutputs } from '../src/currency/outputs.js';
import { CURRENCY_OPTION, type CurrencyDefinitionInput } from '../src/currency/definition.js';

const VRSCTEST = 'iJhCezBExJHvtyH3fGhNnt2NhU4Ztkf2yq';
const SECOND = 'iDMAoXEjZLkpofokBGsVwen7YEwo1iujMQ';
const KMERG_ID = 'i4saPv8g6LPx7gmrZ37gX7ghinVv8JEATr';

// The `identity` object exactly as the lite node's getidentity returns it.
const KMERG_IDENTITY = {
  version: 3,
  flags: 0,
  primaryaddresses: ['RNsCdMnAFWVmtbhvVGfzyeUcEQ3o1h5hZh'],
  minimumsignatures: 1,
  name: 'kmerg',
  identityaddress: KMERG_ID,
  parent: VRSCTEST,
  systemid: VRSCTEST,
  contentmap: {},
  contentmultimap: {},
  revocationauthority: KMERG_ID,
  recoveryauthority: KMERG_ID,
  timelock: 0,
};

// launchFee = 200 native (importFee = 100 native = 10_000_000_000 sat, half the fee).
const LAUNCH_FEE_SATS = 20_000_000_000n;

const TOKEN_INPUT: CurrencyDefinitionInput = {
  name: 'kmerg',
  parent: VRSCTEST,
  options: CURRENCY_OPTION.TOKEN, // 0x20
  proofProtocol: 2,
  startBlock: 1_155_538,
  idRegistrationFees: 100_000_000n, // 1 native
  idReferralLevels: 3,
  preAllocations: [{ address: KMERG_ID, amount: 100_00000000n }],
};
const TOKEN_HEIGHT = 1_155_439;
const TOKEN_OUTPUTS = [
  '',
  '',
  '',
  '',
  '',
  '2704030001012103b99d7cb946c5b1f8a54cde49b8d7e0a2a15a22639feb798009f82b519526c050cc4c5604030b01012103b99d7cb946c5b1f8a54cde49b8d7e0a2a15a22639feb798009f82b519526c0502e01a6ef9ea235635e328124ff3429db9f9e91b64e2da49faec7000f542a851b1d74e4f391d3f4843bbd6b2bdc193075',
  '050403000000cc1b040300010115040f542a851b1d74e4f391d3f4843bbd6b2bdc193075',
];

const BASKET_INPUT: CurrencyDefinitionInput = {
  name: 'kmerg',
  parent: VRSCTEST,
  options: CURRENCY_OPTION.TOKEN | CURRENCY_OPTION.FRACTIONAL, // 0x21
  notarizationProtocol: 1,
  proofProtocol: 1,
  startBlock: 1_160_000,
  idRegistrationFees: 100_000_000n,
  idReferralLevels: 3,
  currencies: [VRSCTEST, SECOND],
  weights: [40_000_000n, 40_000_000n], // 0.4/0.4 → normalized 0.5/0.5
  initialSupply: 1_000_000_000_000n, // 10000
  minPreconversion: [10_000_000_000n, 5_000_000_000n],
  preLaunchDiscount: 5_000_000n,
};
const BASKET_HEIGHT = 1_155_466;
const BASKET_OUTPUTS = [
  '',
  '',
  '',
  '',
  '',
  '2704030001012103b99d7cb946c5b1f8a54cde49b8d7e0a2a15a22639feb798009f82b519526c050cc4c5604030b01012103b99d7cb946c5b1f8a54cde49b8d7e0a2a15a22639feb798009f82b519526c0502e01a6ef9ea235635e328124ff3429db9f9e91b64e2da49faec7000f542a851b1d74e4f391d3f4843bbd6b2bdc193075',
  '050403000000cc1b040300010115040f542a851b1d74e4f391d3f4843bbd6b2bdc193075',
];

describe('buildCurrencyLaunchOutputs — byte-locked against live definecurrency', () => {
  it('reproduces all 7 outputs of a token launch', () => {
    const outs = buildCurrencyLaunchOutputs(TOKEN_INPUT, {
      identity: KMERG_IDENTITY,
      height: TOKEN_HEIGHT,
      launchFeeSats: LAUNCH_FEE_SATS,
    });
    expect(outs.ordered.map((o) => o.script)).toEqual(TOKEN_OUTPUTS);
    expect(outs.reserveDeposit.value).toBe(10_000_000_000n);
  });

  it('reproduces all 7 outputs of a fractional basket launch (normalized weights + discount + preconvert)', () => {
    const outs = buildCurrencyLaunchOutputs(BASKET_INPUT, {
      identity: KMERG_IDENTITY,
      height: BASKET_HEIGHT,
      launchFeeSats: LAUNCH_FEE_SATS,
    });
    expect(outs.ordered.map((o) => o.script)).toEqual(BASKET_OUTPUTS);
  });

  it('exposes outputs both by name and in transaction order', () => {
    const outs = buildCurrencyLaunchOutputs(TOKEN_INPUT, {
      identity: KMERG_IDENTITY,
      height: TOKEN_HEIGHT,
      launchFeeSats: LAUNCH_FEE_SATS,
    });
    expect(outs.ordered).toEqual([
      outs.identityUpdate, outs.currencyDefinition, outs.import,
      outs.notarization, outs.export, outs.reserveDeposit, outs.change,
    ]);
  });

  it('rejects a non-positive launch fee', () => {
    expect(() =>
      buildCurrencyLaunchOutputs(TOKEN_INPUT, { identity: KMERG_IDENTITY, height: TOKEN_HEIGHT, launchFeeSats: 0n }),
    ).toThrow(/launchFeeSats must be positive/);
  });

  it('rejects a missing identity address', () => {
    expect(() =>
      buildCurrencyLaunchOutputs(TOKEN_INPUT, { identity: {}, height: TOKEN_HEIGHT, launchFeeSats: LAUNCH_FEE_SATS }),
    ).toThrow(/identityaddress is required/);
  });

  it('rejects an identity whose address does not match the currency name + parent', () => {
    // A different i-address for the "kmerg" definition — the currency id derived
    // from name+parent no longer matches, so the launch would be daemon-rejected.
    const wrong = { ...KMERG_IDENTITY, identityaddress: 'iGfe9Pur1yEwWYE52hpb533YBpQpU4uvzt' };
    expect(() =>
      buildCurrencyLaunchOutputs(TOKEN_INPUT, { identity: wrong, height: TOKEN_HEIGHT, launchFeeSats: LAUNCH_FEE_SATS }),
    ).toThrow(/identity mismatch/);
  });

  it('rejects a start block at or below the current height', () => {
    // startBlock 1_155_538 with height 1_155_538 (not in the future).
    expect(() =>
      buildCurrencyLaunchOutputs(TOKEN_INPUT, { identity: KMERG_IDENTITY, height: 1_155_538, launchFeeSats: LAUNCH_FEE_SATS }),
    ).toThrow(/must be greater than the current height/);
  });

  it('rejects an identity that already has an active currency', () => {
    const used = { ...KMERG_IDENTITY, flags: 1 }; // FLAG_ACTIVECURRENCY already set
    expect(() =>
      buildCurrencyLaunchOutputs(TOKEN_INPUT, { identity: used, height: TOKEN_HEIGHT, launchFeeSats: LAUNCH_FEE_SATS }),
    ).toThrow(/already has an active currency/);
  });

  it('rejects a systemId that is not the chain', () => {
    const otherSystem = { ...KMERG_IDENTITY, systemid: 'iGfe9Pur1yEwWYE52hpb533YBpQpU4uvzt' };
    expect(() =>
      buildCurrencyLaunchOutputs(TOKEN_INPUT, { identity: otherSystem, height: TOKEN_HEIGHT, launchFeeSats: LAUNCH_FEE_SATS }),
    ).toThrow(/must equal the chain system id/);
  });

  it('rounds the reserve deposit up for an odd launch fee (import share = ceil)', () => {
    const outs = buildCurrencyLaunchOutputs(TOKEN_INPUT, { identity: KMERG_IDENTITY, height: TOKEN_HEIGHT, launchFeeSats: 3n });
    expect(outs.reserveDeposit.value).toBe(2n); // 3 - (3 >> 1) = 2, not 1
  });

  // An NFT (tokenized ID control) launch, byte-locked against the live-accepted
  // daemon tx (kmerg NFT, def tx 8d8671d4…) at height 1156133. Exercises the NFT
  // path: identity output with TOKENIZED_ID_CONTROL, the native-currency-mapped
  // state (weight [0], supply 1 satoshi), and the reduced NFT launch fee.
  const NFT_INPUT: CurrencyDefinitionInput = {
    name: 'kmerg',
    parent: VRSCTEST,
    options: CURRENCY_OPTION.TOKEN | CURRENCY_OPTION.SINGLECURRENCY | CURRENCY_OPTION.NFT_TOKEN,
    proofProtocol: 1,
    notarizationProtocol: 1,
    startBlock: 1_156_183,
    preAllocations: [{ address: KMERG_ID, amount: 1n }],
    idRegistrationFees: 100_000_000n,
    idReferralLevels: 3,
  };
  const NFT_HEIGHT = 1_156_133;
  const NFT_LAUNCH_FEE = 2_000_000n; // idImportFees (0.02) → reserve deposit 0.01
  const NFT_OUTPUTS = [
    '',
    '',
    '',
    '',
    '',
    '2704030001012103b99d7cb946c5b1f8a54cde49b8d7e0a2a15a22639feb798009f82b519526c050cc4c5404030b01012103b99d7cb946c5b1f8a54cde49b8d7e0a2a15a22639feb798009f82b519526c0502c01a6ef9ea235635e328124ff3429db9f9e91b64e2dbc83400f542a851b1d74e4f391d3f4843bbd6b2bdc193075',
    '050403000000cc1b040300010115040f542a851b1d74e4f391d3f4843bbd6b2bdc193075',
  ];

  it('reproduces all 7 outputs of an NFT (tokenized ID control) launch', () => {
    const outs = buildCurrencyLaunchOutputs(NFT_INPUT, {
      identity: KMERG_IDENTITY,
      height: NFT_HEIGHT,
      launchFeeSats: NFT_LAUNCH_FEE,
    });
    expect(outs.ordered.map((o) => o.script)).toEqual(NFT_OUTPUTS);
    expect(outs.reserveDeposit.value).toBe(1_000_000n); // 0.01 native
  });
});
